<input
  type="text"
  autoFocus
  className="..."
  defaultValue={remarksMap[issue.id] ?? issue.remarks}
  onKeyDown={(e) => {
    if (e.key === "Enter") {
      const value = e.currentTarget.value;
      setRemarksMap((prev) => ({ ...prev, [issue.id]: value }));
      onRemarksChange?.(issue.id, value);
      setEditingIssueId(null);
    }
    if (e.key === "Escape") {
      setEditingIssueId(null);
    }
  }}
/>
```

